'use client';
import styles from './Navbar.module.css';
import Link from 'next/link';

export default function Navbar() {
    return (
        <div style={{ padding: '16px', background: '#000', position: 'sticky', top: 0, zIndex: 100 }}>
            {/* Main Nav */}
            <nav className={styles.nav}>
                <Link href="#" className={styles.navLogo}>
                    <div className={styles.logoIcon}>
                        <svg width="28" height="28" viewBox="0 0 28 28" fill="none" xmlns="http://www.w3.org/2000/svg">
                            <rect width="28" height="28" rx="5" fill="#000" />
                            <rect x="5" y="5" width="7" height="18" fill="#FDDD23" />
                            <rect x="15" y="5" width="7" height="8" fill="#FDDD23" />
                        </svg>
                    </div>
                    <div className={styles.logoText}>
                        <span className={styles.brandName}>Call Bridge</span>
                    </div>
                </Link>

                <ul className={styles.navLinks}>
                    <li className={styles.navItem}><Link href="#">Home</Link></li>
                    <li className={styles.navItem}><Link href="#">How It Works</Link></li>
                    <li className={styles.navItem}><Link href="#">Lead Types</Link></li>
                    <li className={styles.navItem}><Link href="#">Pricing</Link></li>
                    <li className={styles.navItem}><Link href="#">About</Link></li>
                    <li className={styles.navItem}><Link href="#">Contact</Link></li>
                </ul>

                <div className={styles.navActions}>
                    <Link href="#" className={styles.btnLogin}>Log In</Link>
                    <Link href="#" className={styles.btnApply}>Book a Demo</Link>
                </div>
            </nav>
        </div>
    );
}
