'use client';
import { useState } from 'react';
import styles from './Testimonials.module.css';

interface Testimonial {
    company: string;
    role: string;
    name: string;
    text: string;
    logoBg: string;
    logoText: string;
    logoColor?: string;
}

const testimonials: Testimonial[] = [
    {
        company: 'Adidas',
        role: 'Managing Director, Adidas',
        name: 'Paddy Muldoon',
        text: "Introducing an alternative payment option to customers has enabled our Adidas retail business to extend its reach. Access to the PayJustNow team, the integration into our Adidas payment portal, and the end-use consumer experience have been nothing short of seamless. This has led to increased conversions, sales and repeat business. We are excited about future growth with the PayJustNow team.",
        logoBg: '#f0ede6',
        logoText: 'adidas',
        logoColor: '#000',
    },
    {
        company: 'GoMaxx',
        role: 'Business Owner, GoMaxx',
        name: 'James Taylor',
        text: "Signing up with PayJustNow opened a whole new market segment for our business. We now provide customers with interest & fee-free payment terms, PayJustNow promotes our brand to new pre-approved customers within the ecosystem, and its online and in-store functionality supports our omnichannel approach.",
        logoBg: '#e8f5ff',
        logoText: 'gomaxx.',
        logoColor: '#0066cc',
    },
    {
        company: 'Puma',
        role: 'Marketing Director, Puma',
        name: 'Nathier Schroeder',
        text: "As a leading sports brand, Puma has always been committed to providing exceptional experiences for our customers. When we partnered with PayJustNow, we were impressed by their innovative payment solution.",
        logoBg: '#fff3e0',
        logoText: 'PUMA',
        logoColor: '#222',
    },
    {
        company: 'Cape Union Mart',
        role: 'Marketing Team, Cape Union Mart',
        name: 'Marketing Team',
        text: "PayJustNow gives Cape Union Mart a big advantage by offering customers a simple and adaptable payment option. Our customers stretch the cost over time and avoid interest by paying in instalments. This means more sales potential for Cape Union Mart, fewer financial obstacles for customers, and bigger purchases.",
        logoBg: '#e8f5e9',
        logoText: 'Cape Union Mart',
        logoColor: '#2e7d32',
    },
];

export default function Testimonials() {
    const [idx, setIdx] = useState(0);
    const visible = [testimonials[idx % testimonials.length], testimonials[(idx + 1) % testimonials.length]];

    return (
        <section className={styles.section}>
            <div className={styles.layout}>
                <div className={styles.left}>
                    <h2 className={styles.heading}>WHY BUSINESSES LOVE PAYJUSTNOW</h2>
                    <div className={styles.navBtns}>
                        <button className={styles.navBtn} onClick={() => setIdx((p) => (p - 1 + testimonials.length) % testimonials.length)}>←</button>
                        <button className={styles.navBtn} onClick={() => setIdx((p) => (p + 1) % testimonials.length)}>→</button>
                    </div>
                </div>
                <div className={styles.cards}>
                    {visible.map((t, i) => (
                        <div className={styles.card} key={i}>
                            <div className={styles.logo} style={{ background: t.logoBg }}>
                                <span style={{ fontSize: 11, fontWeight: 800, color: t.logoColor }}>{t.logoText}</span>
                            </div>
                            <p className={styles.role}>{t.role}</p>
                            <h3 className={styles.name}>{t.name}</h3>
                            <p className={styles.text}>{t.text}</p>
                        </div>
                    ))}
                </div>
            </div>
        </section>
    );
}
