'use client';
import { useEffect, useRef, useState } from 'react';
import styles from './HowItWorks.module.css';

const PhoneIcon = () => (
    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M22 16.92v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07A19.5 19.5 0 013.07 9.8 19.79 19.79 0 01.01 1.18 2 2 0 012 0h3a2 2 0 012 1.72c.127.96.361 1.903.7 2.81a2 2 0 01-.45 2.11L6.09 7.91a15.998 15.998 0 006 6l1.27-1.27a2 2 0 012.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0122 14.92z" />
    </svg>
);
const SearchIcon = () => (
    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="11" cy="11" r="8" />
        <line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
);
const CheckIcon = () => (
    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
        <polyline points="20 6 9 17 4 12" />
    </svg>
);
const RocketIcon = () => (
    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M4.5 16.5c-1.5 1.26-2 5-2 5s3.74-.5 5-2c.71-.84.7-2.13-.09-2.91a2.18 2.18 0 00-2.91-.09z" />
        <path d="M12 15l-3-3a22 22 0 012-3.95A12.88 12.88 0 0122 2c0 2.72-.78 7.5-6 11a22.35 22.35 0 01-4 2z" />
        <path d="M9 12H4s.55-3.03 2-4c1.62-1.08 5 0 5 0M15 12v5s3.03-.55 4-2c1.08-1.62 0-5 0-5" />
    </svg>
);

const cards = [
    {
        label: '1 — Outreach',
        Icon: PhoneIcon,
        desc: 'Our trained US-based call center agents proactively contact potential prospects, identifying decision-makers and initiating meaningful conversations at scale.',
        step: 'STEP 1',
        bg: '#F0EDE6',
        color: '#000',
        valueSize: 'clamp(72px, 10vw, 140px)',
    },
    {
        label: '2 — Qualification',
        Icon: SearchIcon,
        desc: 'We rigorously verify key qualifying details including age, zip code, and insurance interest to ensure every lead meets your exact criteria before you ever pick up the phone.',
        step: 'STEP 2',
        bg: '#E2E0D8',
        color: '#000',
        valueSize: 'clamp(52px, 7vw, 108px)',
    },
    {
        label: '3 — Interest Confirmed',
        Icon: CheckIcon,
        desc: 'Once the prospect clearly and verbally confirms their interest in your product or service, the call is flagged, reviewed, and prepared for an immediate live transfer to your team.',
        step: 'STEP 3',
        bg: '#2a2a2a',
        color: '#fff',
        valueSize: 'clamp(48px, 6.5vw, 100px)',
    },
    {
        label: '4 — Live Transfer',
        Icon: RocketIcon,
        desc: 'The fully qualified, interested prospect is transferred directly to your phone in real time — no delays, no cold leads, just warm conversations with people ready to buy.',
        step: 'STEP 4',
        bg: '#C8C5B0',
        color: '#000',
        valueSize: 'clamp(72px, 10vw, 140px)',
    },
];

// How many px of the previous card stays visible above the next one
const PEEK = 120;
// Where card 1 sticks from the top of the viewport
const FIRST_TOP = 70;

export default function HowItWorks() {
    const wrapperRef = useRef<HTMLDivElement>(null);
    const lastCardRef = useRef<HTMLDivElement>(null);
    const [lastCardUnstuck, setLastCardUnstuck] = useState(false);

    useEffect(() => {
        const onScroll = () => {
            if (!wrapperRef.current || !lastCardRef.current) return;
            const wrapperRect = wrapperRef.current.getBoundingClientRect();
            const lastTop = FIRST_TOP + (cards.length - 1) * PEEK;
            const cardHeight = lastCardRef.current.offsetHeight;
            // Card 4 unsticks when the wrapper bottom can't hold it at its sticky top
            const unstickThreshold = lastTop + cardHeight;
            setLastCardUnstuck(wrapperRect.bottom < unstickThreshold);
        };
        window.addEventListener('scroll', onScroll, { passive: true });
        return () => window.removeEventListener('scroll', onScroll);
    }, []);

    return (
        <section className={styles.section}>
            <div className={styles.header}>
                <h2 className={styles.title}>HOW IT WORKS</h2>
            </div>

            <div className={styles.stackWrapper} ref={wrapperRef}>
                {cards.map((card, i) => {
                    const isLast = i === cards.length - 1;
                    return (
                    <div
                        key={card.step}
                        ref={isLast ? lastCardRef : undefined}
                        className={styles.stickySlot}
                        style={{
                            top: `${FIRST_TOP + i * PEEK}px`,
                            zIndex: isLast && lastCardUnstuck ? 0 : i + 1,
                            background: card.bg,
                        }}
                    >
                        <div
                            className={styles.card}
                            style={{ background: card.bg, color: card.color }}
                        >
                            <div className={styles.top}>
                                <span className={styles.cardLabel}>{card.label}</span>
                                <span className={styles.cardIcon}><card.Icon /></span>
                            </div>
                            <div
                                className={styles.cardValue}
                                style={{ color: card.color, fontSize: card.valueSize }}
                            >
                                {card.step}
                            </div>
                            <p className={styles.cardDesc}>{card.desc}</p>
                        </div>
                    </div>
                    );
                })}
            </div>

            <p className={styles.desc}>
                Our seamless B2B workflow ensures you only speak to highly qualified prospects —
                every call is screened, confirmed, and transferred in real time so your team
                never wastes a moment on unqualified leads.
            </p>
        </section>
    );
}
