'use client';
import { useState } from 'react';
import styles from './SeamlessCheckout.module.css';

const tabs = ['eCommerce', 'POS Integration', 'Soft Touch Integration'];

const tabContent: Record<string, { title: string; body: string }> = {
    'eCommerce': {
        title: 'eCommerce',
        body: 'Our prebuilt plugins are compatible with Shopify, Magento, WooCommerce, Salesforce Shopstar, PrestaShop and Storefront. Plus, you can tailor our integration to suit your business needs.',
    },
    'POS Integration': {
        title: 'POS Integration',
        body: 'Seamless POS integration through ACS, Cow Hills, BCX, Posworx or Yoyo. We are constantly expanding our list of POS partners to keep your payment process smooth and convenient.',
    },
    'Soft Touch Integration': {
        title: 'Soft Touch Integration',
        body: 'Use our PayUp merchant app or static QR codes to get up and running in minutes. Cashless payments speed up the checkout process, reduce queues, and keep shoppers coming back for your service and convenience.',
    },
};

export default function SeamlessCheckout() {
    const [active, setActive] = useState('eCommerce');

    return (
        <section className={styles.section}>
            <div className={styles.header}>
                <div>
                    <span className={styles.tag}>Omni-channel Solutions</span>
                    <h2 className={styles.title}>SEAMLESS CHECKOUT<br />WHEREVER THEY SHOP</h2>
                </div>
                <p className={styles.desc}>
                    Offer shoppers the convenience of fast checkouts online and in-store with the PayJustNow app.
                </p>
            </div>
            <div className={styles.tabs}>
                {tabs.map((t) => (
                    <button
                        key={t}
                        className={`${styles.tab} ${active === t ? styles.tabActive : ''}`}
                        onClick={() => setActive(t)}
                    >
                        {t}
                    </button>
                ))}
            </div>
            <div className={styles.cards}>
                {tabs.map((t) => (
                    <div
                        key={t}
                        className={`${styles.card} ${active === t ? styles.cardActive : ''}`}
                    >
                        <h3 className={styles.cardTitle}>{tabContent[t].title}</h3>
                        <p className={styles.cardBody}>{tabContent[t].body}</p>
                    </div>
                ))}
            </div>
        </section>
    );
}
